let num_tentativas_pid = parseInt(context.attributes.api_pid_numero_tentativas);

let increment = num_tentativas_pid + 1;

context.setAttribute('api_pid_numero_tentativas', increment)

let apiResult = context.attributes.api_pid_validacao_response;

let respostaPid = apiResult.statusValidacoes[0].status;

const transformarRespostaPid = respostaPid => (respostaPid == true ? 1 : 0);

var resultado = transformarRespostaPid(respostaPid);
context.setAttribute('apiResult ', 'abacate');
context.setAttribute('resposta_pid', resultado);

let apiResult = context.attributes.api_pid_perguntas_response;
let respostaPid = apiResult.statusValidacoes[0].status;

const transformarRespostaPid = respostaPid => (respostaPid == true ? 1 : 0);

var resultado = transformarRespostaPid(respostaPid);
context.setAttribute('resposta_pid', resultado);

let respostas_corretas = parseInt(context.attributes.api_pid_respostas_corretas) || 0;

let increment = respostas_corretas + 1;

context.setAttribute('api_pid_respostas_corretas', increment)

// Pegando o resultado da API
let apiResult = context.attributes.api_azure_ad_usuario_status_response;

// Atribuindo os valores às variáveis do flow
context.setAttribute('usuario_status', apiResult.status);
context.setAttribute('usuario_data_retorno_ferias', apiResult.dataRetorno)

let tent_nova_senha = parseInt(context.attributes.tent_nova_senha) || 0;

let increment = tent_nova_senha + 1;

context.setAttribute('tent_nova_senha', increment)

var senha = context.attributes.nova_senha_usuario;
var senhaOk = false;

var formatEspecial = /[ `!@#$%^&*()_+\-=\[\]{};':"\\|,.<>\/?~]/;
var formatUppercase = /[A-Z]/;
var formatNumber = /[0-9]/;
var formatLength = /^.{8,}$/;

if (formatEspecial.test(senha) && formatUppercase.test(senha) && formatNumber.test(senha) && formatLength.test(senha)) {
  // Verifica se a senha contém "algar" de forma case-insensitive
  if (senha.toLowerCase().includes("algar".toLowerCase())) {
    senhaOk = false;
  } else {
    senhaOk = true;
  }
} else {
    senhaOk = false;
}

if (senhaOk) {
    context.setAttribute('senha_usuario_valida', 'Sim')
} else {
    context.setAttribute('senha_usuario_valida', 'Não')
}

let json = context.attributes.api_pid_perguntas_response;
let letra = "";
for (var i in json) {
    if (i == 0) { letra = "a"; }
    else if (i == 1) { letra = "b"; }
    else if (i == 2) { letra = "c"; }
    else if (i == 3) { letra = "d"; }
    else if (i == 4) { letra = "e"; }
	context.setAttribute('pergunta_pid_'+letra, ''+json[i].pid);
	context.setAttribute('frase_pergunta_pid_'+letra, ''+json[i].pergunta);

}

let apiResult = context.attributes.api_cervello_abertura_chamado_response;
let chamado = apiResult.chamado;

context.setAttribute('numeroChamadoBilhetagem', chamado);

let reset_tentativas_verificar_usuario = parseInt(context.attributes.reset_tentativas_verificar_usuario || 0);

let increment = reset_tentativas_verificar_usuario + 1;

context.setAttribute('reset_tentativas_verificar_usuario', increment)

let letra = context.attributes.api_pid_letra_pergunta;

let json_string = '' +
'{' +
    '"validacao": [' +
        '{' +
            '"pid": "' + context.attributes['pergunta_pid_' + letra] + '",' +
            '"resposta": "' + context.attributes.api_pid_resposta_usuario + '"' +
        '}' +
    ']' +       
'}';

context.setAttribute('body_validacao_pid', json_string);

context.setAttribute('debug_letra', letra);

// Pegando o resultado da API
let apiResult = context.attributes.result;

// Atribuindo os valores às variáveis do flow
context.setAttribute('usuario_nomeCompleto', apiResult.nome);
context.setAttribute('usuario_email', apiResult.email);
context.setAttribute('usuario_login', apiResult.login);

// Pegando o nome completo
let nomeCompleto = apiResult.nome;

// Extraindo o primeiro nome
let primeiroNome = nomeCompleto.split(' ')[0];

// Convertendo primeira letra em maiúscula e restante em minúscula
primeiroNome = primeiroNome.charAt(0).toUpperCase() + primeiroNome.slice(1).toLowerCase();

// Salvando o primeiro nome na variável
context.setAttribute('usuario_nome', primeiroNome);
